import { Component, HostListener } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';

interface VehicleType {
  id: string;
  name: string;
  type: string;
  description: string;
  iconImage: string; // Imagen para la tarjeta
  images: { [key: number]: string }; // Imágenes para 360°
  features: string[];
  specs: { label: string; value: string; }[];
}

interface Equipment {
  id: string;
  name: string;
  category: string;
  description: string;
  icon: string;
  specs: { label: string; value: string; }[];
}

@Component({
  selector: 'app-proteccion-ejecutiva',
  standalone: true,
  imports: [CommonModule, NavbarComponent],
  template: `
    <app-navbar></app-navbar>
    
    <!-- ... Hero section igual ... -->
    
    <!-- SELECTOR DE VEHÍCULOS -->
    <section class="section vehicles-section">
      <div class="container">
        <div class="section-header">
          <h2>Configure Su Vehículo Blindado</h2>
          <p class="section-subtitle">
            Seleccione el tipo de carrocería que mejor se adapte a sus necesidades
          </p>
        </div>

        <div class="vehicle-selector">
          <h3>1. Seleccione el Tipo de Carrocería</h3>
          <div class="vehicle-types-grid">
            <div class="vehicle-type-card" 
                 *ngFor="let vehicle of vehicleTypes"
                 [class.active]="selectedVehicle?.id === vehicle.id"
                 (click)="selectVehicle(vehicle)">
              <div class="vehicle-icon-container">
                <img [src]="vehicle.iconImage" [alt]="vehicle.name" class="vehicle-icon-img">
              </div>
              <h4>{{ vehicle.name }}</h4>
              <p class="vehicle-type-label">{{ vehicle.type }}</p>
            </div>
          </div>
        </div>

        <!-- VISUALIZACIÓN 360° INTERACTIVA -->
        <div class="vehicle-details" *ngIf="selectedVehicle">
          <div class="vehicle-display">
            <div class="vehicle-360">
              <!-- Controles de rotación -->
              <div class="rotation-controls">
                <button class="rotation-btn" 
                        (mousedown)="startRotation('left')"
                        (mouseup)="stopRotation()"
                        (mouseleave)="stopRotation()"
                        (touchstart)="startRotation('left')"
                        (touchend)="stopRotation()">
                  ←
                </button>
                <div class="rotation-info">
                  <span class="rotation-indicator">{{ currentRotation }}°</span>
                  <span class="rotation-hint-mini">Mantén presionado para rotar</span>
                </div>
                <button class="rotation-btn" 
                        (mousedown)="startRotation('right')"
                        (mouseup)="stopRotation()"
                        (mouseleave)="stopRotation()"
                        (touchstart)="startRotation('right')"
                        (touchend)="stopRotation()">
                  →
                </button>
              </div>

              <!-- Vista del vehículo con drag -->
              <div class="vehicle-view"
                   (mousedown)="startDrag($event)"
                   (touchstart)="startDrag($event)">
                <img [src]="getCurrentVehicleImage()" 
                     [alt]="selectedVehicle.name"
                     class="vehicle-image"
                     [style.transform]="'scale(' + imageScale + ')'">
                
                <!-- Indicador de carga -->
                <div class="loading-indicator" *ngIf="isLoadingImage">
                  <div class="spinner"></div>
                </div>
              </div>

              <p class="rotation-hint">
                ← Mantén presionado las flechas o arrastra para rotar → 
              </p>

              <!-- Barra de progreso de rotación -->
              <div class="rotation-progress">
                <div class="progress-bar" [style.width.%]="(currentRotation / 360) * 100"></div>
              </div>
            </div>

            <!-- Información del vehículo (igual que antes) -->
            <div class="vehicle-info">
              <h3>{{ selectedVehicle.name }}</h3>
              <p class="vehicle-description">{{ selectedVehicle.description }}</p>
              
              <div class="vehicle-features">
                <h4>Características Incluidas:</h4>
                <ul>
                  <li *ngFor="let feature of selectedVehicle.features">
                    <span class="check-icon">✓</span>
                    {{ feature }}
                  </li>
                </ul>
              </div>

              <div class="vehicle-specs">
                <h4>Especificaciones de Blindaje:</h4>
                <div class="spec-item" *ngFor="let spec of selectedVehicle.specs">
                  <span class="spec-label">{{ spec.label }}</span>
                  <span class="spec-value">{{ spec.value }}</span>
                </div>
              </div>

              <!-- Botón de reset -->
              <button class="btn btn-outline" (click)="resetRotation()">
                🔄 Restablecer Vista
              </button>
            </div>
          </div>
        </div>

        <!-- Resto del código igual (equipamiento, resumen, etc.) -->
      </div>
    </section>
  `,
  styles: [`
    /* Estilos anteriores + estos nuevos */

    .vehicle-icon-img {
      width: 100%;
      height: 100%;
      object-fit: contain;
    }

    .rotation-info {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 5px;
    }

    .rotation-hint-mini {
      font-size: 11px;
      color: var(--text-muted);
      text-align: center;
    }

    .vehicle-view {
      width: 100%;
      max-width: 500px;
      height: 350px;
      display: flex;
      align-items: center;
      justify-content: center;
      position: relative;
      cursor: grab;
      user-select: none;
      
      &:active {
        cursor: grabbing;
      }
    }

    .vehicle-image {
      width: 100%;
      height: 100%;
      object-fit: contain;
      transition: transform 0.1s ease;
      pointer-events: none;
    }

    .loading-indicator {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
    }

    .spinner {
      width: 40px;
      height: 40px;
      border: 4px solid rgba(229, 198, 67, 0.2);
      border-top-color: var(--primary-gold);
      border-radius: 50%;
      animation: spin 0.8s linear infinite;
    }

    @keyframes spin {
      to { transform: rotate(360deg); }
    }

    .rotation-progress {
      width: 100%;
      height: 6px;
      background: rgba(0, 0, 0, 0.1);
      border-radius: 10px;
      overflow: hidden;
      margin-top: 20px;
    }

    .progress-bar {
      height: 100%;
      background: linear-gradient(90deg, var(--primary-gold), var(--primary-gold-dark));
      transition: width 0.1s ease;
      border-radius: 10px;
    }

    .rotation-btn {
      user-select: none;
      
      &:active {
        transform: scale(0.9);
      }
    }

    .btn-outline {
      background: transparent;
      border: 2px solid var(--primary-gold);
      color: var(--primary-gold);
      
      &:hover {
        background: var(--primary-gold);
        color: var(--dark-primary);
      }
    }
  `]
})
export class ProteccionEjecutivaComponent {
  selectedVehicle: VehicleType | null = null;
  selectedEquipment: Equipment[] = [];
  currentRotation: number = 0;
  isLoadingImage: boolean = false;
  imageScale: number = 1;

  // Variables para rotación continua
  private rotationInterval: any = null;
  private rotationSpeed: number = 2; // grados por frame
  
  // Variables para drag
  private isDragging: boolean = false;
  private lastDragX: number = 0;
  private dragSensitivity: number = 0.5;

  vehicleTypes: VehicleType[] = [
    {
      id: 'sedan',
      name: 'Sedán',
      type: 'Ejecutivo',
      description: 'Vehículo sedán blindado ideal para desplazamientos ejecutivos discretos.',
      iconImage: 'assets/vehicles/sedan/0.png',
      images: {
        0: 'assets/vehicles/sedan/0.png',
        90: 'assets/vehicles/sedan/90.png',
        180: 'assets/vehicles/sedan/180.png',
        270: 'assets/vehicles/sedan/270.png'
      },
      features: [
        'Blindaje certificado nivel B6/B7',
        'Vidrios anti-bala de 4 capas',
        'Sistema de escape a prueba de explosivos',
        'Neumáticos run-flat',
        'GPS y comunicación satelital',
        'Capacidad: 4-5 pasajeros'
      ],
      specs: [
        { label: 'Blindaje', value: 'Nivel B6/B7' },
        { label: 'Pasajeros', value: '4-5' },
        { label: 'Autonomía', value: '600 km' },
        { label: 'Peso adicional', value: '+800 kg' }
      ]
    },
    {
      id: 'suv',
      name: 'SUV',
      type: 'Versátil',
      description: 'SUV blindado de alto rendimiento, perfecto para terrenos variados.',
      iconImage: 'assets/vehicles/suv/0.png',
      images: {
        0: 'assets/vehicles/suv/0.png',
        90: 'assets/vehicles/suv/90.png',
        180: 'assets/vehicles/suv/180.png',
        270: 'assets/vehicles/suv/270.png'
      },
      features: [
        'Blindaje certificado nivel B6',
        'Suspensión reforzada',
        'Sistema 4x4 con control de tracción',
        'Vidrios polarizados anti-bala',
        'Sistema de comunicación avanzado',
        'Capacidad: 5-7 pasajeros'
      ],
      specs: [
        { label: 'Blindaje', value: 'Nivel B6' },
        { label: 'Pasajeros', value: '5-7' },
        { label: 'Autonomía', value: '700 km' },
        { label: 'Peso adicional', value: '+1000 kg' }
      ]
    },
    {
      id: 'todoterreno',
      name: 'Todoterreno',
      type: 'Extremo',
      description: 'Vehículo todoterreno blindado para zonas de difícil acceso.',
      iconImage: 'assets/vehicles/todoterreno/0.png',
      images: {
        0: 'assets/vehicles/todoterreno/0.png',
        90: 'assets/vehicles/todoterreno/90.png',
        180: 'assets/vehicles/todoterreno/180.png',
        270: 'assets/vehicles/todoterreno/270.png'
      },
      features: [
        'Blindaje militar nivel B7',
        'Suspensión off-road reforzada',
        'Protección de bajos y tanque',
        'Tracción total permanente',
        'Neumáticos todoterreno run-flat',
        'Capacidad: 4-5 pasajeros'
      ],
      specs: [
        { label: 'Blindaje', value: 'Nivel B7' },
        { label: 'Pasajeros', value: '4-5' },
        { label: 'Autonomía', value: '650 km' },
        { label: 'Peso adicional', value: '+1200 kg' }
      ]
    },
    {
      id: 'pickup',
      name: 'Pick-up',
      type: 'Operativo',
      description: 'Camioneta pick-up blindada para logística y transporte de valores.',
      iconImage: 'assets/vehicles/pickup/0.png',
      images: {
        0: 'assets/vehicles/pickup/0.png',
        90: 'assets/vehicles/pickup/90.png',
        180: 'assets/vehicles/pickup/180.png',
        270: 'assets/vehicles/pickup/270.png'
      },
      features: [
        'Blindaje de cabina nivel B6',
        'Platón reforzado con cobertura',
        'Suspensión heavy-duty',
        'Capacidad de remolque aumentada',
        'GPS y rastreo satelital',
        'Capacidad: 4-5 pasajeros'
      ],
      specs: [
        { label: 'Blindaje', value: 'Nivel B6' },
        { label: 'Pasajeros', value: '4-5' },
        { label: 'Carga', value: '800 kg' },
        { label: 'Peso adicional', value: '+900 kg' }
      ]
    },
    {
      id: 'hatchback',
      name: 'Hatchback',
      type: 'Urbano',
      description: 'Vehículo compacto blindado para desplazamientos urbanos discretos.',
      iconImage: 'assets/vehicles/hatchback/0.png',
      images: {
        0: 'assets/vehicles/hatchback/0.png',
        90: 'assets/vehicles/hatchback/90.png',
        180: 'assets/vehicles/hatchback/180.png',
        270: 'assets/vehicles/hatchback/270.png'
      },
      features: [
        'Blindaje certificado nivel B4/B6',
        'Diseño compacto urbano',
        'Bajo consumo de combustible',
        'Sistema de comunicación integrado',
        'Vidrios anti-bala',
        'Capacidad: 4 pasajeros'
      ],
      specs: [
        { label: 'Blindaje', value: 'Nivel B4/B6' },
        { label: 'Pasajeros', value: '4' },
        { label: 'Autonomía', value: '550 km' },
        { label: 'Peso adicional', value: '+600 kg' }
      ]
    }
  ];

  equipment: Equipment[] = [
    // ... (igual que antes)
  ];

  constructor(private router: Router) {}

  @HostListener('document:mousemove', ['$event'])
  onMouseMove(event: MouseEvent) {
    if (this.isDragging) {
      this.handleDrag(event.clientX);
    }
  }

  @HostListener('document:mouseup')
  onMouseUp() {
    this.isDragging = false;
  }

  @HostListener('document:touchmove', ['$event'])
  onTouchMove(event: TouchEvent) {
    if (this.isDragging && event.touches.length > 0) {
      this.handleDrag(event.touches[0].clientX);
    }
  }

  @HostListener('document:touchend')
  onTouchEnd() {
    this.isDragging = false;
  }

  selectVehicle(vehicle: VehicleType) {
    this.selectedVehicle = vehicle;
    this.currentRotation = 0;
    this.selectedEquipment = [];
    this.preloadImages();
  }

  // Precargar todas las imágenes del vehículo
  preloadImages() {
    if (!this.selectedVehicle) return;
    
    Object.values(this.selectedVehicle.images).forEach(imagePath => {
      const img = new Image();
      img.src = imagePath;
    });
  }

  // Obtener imagen actual basada en rotación
  getCurrentVehicleImage(): string {
    if (!this.selectedVehicle) return '';

    // Normalizar rotación a 0-360
    const normalizedRotation = ((this.currentRotation % 360) + 360) % 360;

    // Determinar qué imagen mostrar basándose en el ángulo
    let closestAngle = 0;
    let minDiff = 360;

    [0, 90, 180, 270].forEach(angle => {
      const diff = Math.min(
        Math.abs(normalizedRotation - angle),
        Math.abs(normalizedRotation - angle + 360),
        Math.abs(normalizedRotation - angle - 360)
      );
      
      if (diff < minDiff) {
        minDiff = diff;
        closestAngle = angle;
      }
    });

    return this.selectedVehicle.images[closestAngle];
  }

  // Iniciar rotación continua (mantener presionado)
  startRotation(direction: 'left' | 'right') {
    this.stopRotation(); // Detener cualquier rotación previa
    
    this.rotationInterval = setInterval(() => {
      if (direction === 'left') {
        this.currentRotation = (this.currentRotation - this.rotationSpeed + 360) % 360;
      } else {
        this.currentRotation = (this.currentRotation + this.rotationSpeed) % 360;
      }
    }, 16); // ~60 FPS
  }

  // Detener rotación
  stopRotation() {
    if (this.rotationInterval) {
      clearInterval(this.rotationInterval);
      this.rotationInterval = null;
    }
  }

  // Iniciar drag
  startDrag(event: MouseEvent | TouchEvent) {
    this.isDragging = true;
    
    if (event instanceof MouseEvent) {
      this.lastDragX = event.clientX;
    } else if (event.touches.length > 0) {
      this.lastDragX = event.touches[0].clientX;
    }
  }

  // Manejar drag
  handleDrag(currentX: number) {
    const deltaX = currentX - this.lastDragX;
    this.currentRotation = (this.currentRotation + deltaX * this.dragSensitivity) % 360;
    
    // Normalizar a 0-360
    if (this.currentRotation < 0) {
      this.currentRotation += 360;
    }
    
    this.lastDragX = currentX;
  }

  // Restablecer rotación
  resetRotation() {
    this.currentRotation = 0;
    this.stopRotation();
  }

  // ... resto de métodos igual
  
  ngOnDestroy() {
    this.stopRotation();
  }
}
